// Generated by Cypress Author — 2026-06-11
// Covers: RPE (Perceived Exertion) section on the Activity Detail page
//   /main/running/activities/:id
//
// Suites:
//   1. RPE Section — renders (section exists, 10 picker buttons)
//   2. RPE Section — null state (prompt shown/hidden based on RPE value)
//   3. RPE Section — axis labels and hover (axis labels, hover description)
//   4. RPE Section — picking and saving (PATCH fired, saved message, deselect)
//   5. RPE Section — session load (RPE * duration_min calculation)
//   6. RPE Section — guide toggle (expand/collapse the Borg CR10 guide table)
//   7. RPE Section — info tooltip (appears on hover over info trigger)

import constants from '../../../fixtures/app-constants.json'

const IDS = constants.test_ids.running_activity_detail
const ACTIVITY_ID = 'test-activity-rpe-001'
const ACTIVITY_ENDPOINT = `/api/running/v1/activities/${ACTIVITY_ID}`
const DETAIL_URL = `/main/running/activities/${ACTIVITY_ID}`
// Activity started 2 hours ago so isOlderThan30Min is true
const STARTED_AT_OLD = new Date(Date.now() - 2 * 60 * 60 * 1000).toISOString()

// ---------------------------------------------------------------------------
// Stub helpers
// ---------------------------------------------------------------------------

function stubActivity(overrides = {}) {
  cy.intercept('GET', ACTIVITY_ENDPOINT, {
    statusCode: 200,
    body: {
      activity: {
        id: ACTIVITY_ID,
        activity_type: 'Run',
        name: 'Morning Run',
        started_at: STARTED_AT_OLD,
        moving_time_sec: 3600,
        duration_sec: 3700,
        distance_m: 10000,
        avg_pace_sec_per_km: 360,
        avg_hr: 155,
        max_hr: 182,
        perceived_exertion: null,
        notes: null,
        zones: null,
        historical_avg_hr: null,
        historical_avg_cadence: null,
        user_max_hr: null,
        efficiency_factor_30d_avg: null,
        source: 'strava',
        gear: null,
        summary_polyline: null,
        ...overrides,
      },
      splits: [],
      laps: [],
      best_efforts: [],
      photos: [],
    },
  }).as('getActivity')
}

function stubSupporting() {
  cy.intercept('GET', '/api/running/v1/dashboard', {
    statusCode: 200,
    body: { training_load: { next_race_goal: null } },
  }).as('getDashboard')

  cy.intercept('GET', '/api/running/v1/race-log*', {
    statusCode: 200,
    body: { data: [] },
  }).as('getRaceLog')

  cy.intercept('GET', '/api/running/v1/health/subjective*', {
    statusCode: 200,
    body: {},
  }).as('getHealth')

  // AI insights — stub to empty so AIInsightCard renders in empty state
  cy.intercept('GET', '/api/running/v1/ai/insights*', {
    statusCode: 200,
    body: { data: [] },
  }).as('getInsight')

  cy.intercept('GET', `${ACTIVITY_ENDPOINT}/streams*`, {
    statusCode: 200,
    body: { data: [] },
  }).as('getStreams')
}

function stubPatch(responseValue) {
  cy.intercept('PATCH', ACTIVITY_ENDPOINT, {
    statusCode: 200,
    body: { data: { id: ACTIVITY_ID, perceived_exertion: responseValue } },
  }).as('patchActivity')
}

function visitAndWait() {
  cy.visit(DETAIL_URL)
  cy.wait('@getActivity')
}

// ---------------------------------------------------------------------------
// 1. RPE Section — renders
// ---------------------------------------------------------------------------

describe('RPE Section — renders', () => {
  beforeEach(() => {
    stubSupporting()
    stubActivity()
    cy.setupApiAuthCookies()
    visitAndWait()
  })

  it('rpe section is present on activity detail page', () => {
    cy.get(`#${IDS.rpe_section}`).should('exist')
  })

  it('renders 10 picker buttons', () => {
    cy.get(`[id^="${IDS.rpe_picker}_"]`).should('have.length', 10)
  })
})

// ---------------------------------------------------------------------------
// 2. RPE Section — null state
// ---------------------------------------------------------------------------

describe('RPE Section — null state', () => {
  it('null-state prompt shows when RPE null and activity older than 30 min', () => {
    cy.setupApiAuthCookies()
    stubSupporting()
    stubActivity({ perceived_exertion: null, started_at: STARTED_AT_OLD })
    visitAndWait()
    cy.get(`#${IDS.rpe_null_prompt}`).should('contain', 'How did this run feel?')
  })

  it('null-state prompt hidden when RPE already set', () => {
    cy.setupApiAuthCookies()
    stubSupporting()
    stubActivity({ perceived_exertion: 5 })
    visitAndWait()
    cy.get(`#${IDS.rpe_null_prompt}`).should('not.exist')
  })
})

// ---------------------------------------------------------------------------
// 3. RPE Section — axis labels and hover
// ---------------------------------------------------------------------------

describe('RPE Section — axis labels and hover', () => {
  beforeEach(() => {
    stubSupporting()
    stubActivity()
    cy.setupApiAuthCookies()
    visitAndWait()
  })

  it('axis labels show when nothing selected or hovered', () => {
    cy.get(`#${IDS.rpe_hover_label}`)
      .scrollIntoView()
      .should('contain', '1 (very easy)')
      .and('contain', '10 (max effort)')
  })

  it('hover on picker button shows label and breathing description', () => {
    cy.get(`#${IDS.rpe_picker}_5_activityDetailPage`).scrollIntoView().realHover()
    cy.get(`#${IDS.rpe_hover_label}`).should('contain', 'Steady')
  })
})

// ---------------------------------------------------------------------------
// 4. RPE Section — picking and saving
// ---------------------------------------------------------------------------

describe('RPE Section — picking and saving', () => {
  beforeEach(() => {
    stubSupporting()
    stubActivity()
    stubPatch(7)
    cy.setupApiAuthCookies()
    visitAndWait()
  })

  it('clicking picker button fires PATCH with correct perceived_exertion', () => {
    cy.get(`#${IDS.rpe_picker}_7_activityDetailPage`).scrollIntoView().click()
    cy.wait('@patchActivity').its('request.body').should('deep.equal', { perceived_exertion: 7 })
  })

  it('saved message appears after successful PATCH', () => {
    cy.get(`#${IDS.rpe_picker}_7_activityDetailPage`).scrollIntoView().click()
    cy.wait('@patchActivity')
    cy.get(`#${IDS.rpe_saved_msg}`).should('contain', 'Saved')
  })

  it('clicking already-selected button sends perceived_exertion null (deselect)', () => {
    // Visit fresh with RPE pre-set to 5
    stubActivity({ perceived_exertion: 5 })
    stubPatch(null)
    cy.setupApiAuthCookies()
    stubSupporting()
    visitAndWait()
    cy.get(`#${IDS.rpe_picker}_5_activityDetailPage`).scrollIntoView().click()
    cy.wait('@patchActivity').its('request.body').should('deep.equal', { perceived_exertion: null })
  })
})

// ---------------------------------------------------------------------------
// 5. RPE Section — session load
// ---------------------------------------------------------------------------

describe('RPE Section — session load', () => {
  it('session load shows correct value (RPE=7, 3600s → 420)', () => {
    cy.setupApiAuthCookies()
    stubSupporting()
    // RPE=7, moving_time_sec=3600 → session load = 7 * (3600/60) = 420
    stubActivity({ perceived_exertion: 7, moving_time_sec: 3600 })
    visitAndWait()
    cy.get(`#${IDS.rpe_session_load}`).scrollIntoView().should('contain', '420')
  })
})

// ---------------------------------------------------------------------------
// 6. RPE Section — guide toggle
// ---------------------------------------------------------------------------

describe('RPE Section — guide toggle', () => {
  beforeEach(() => {
    stubSupporting()
    stubActivity()
    cy.setupApiAuthCookies()
    visitAndWait()
  })

  it('guide toggle expands and collapses the guide table', () => {
    // Guide table hidden initially
    cy.get(`#${IDS.rpe_guide_table}`).should('not.exist')

    // Expand
    cy.get(`#${IDS.rpe_guide_toggle}`).scrollIntoView().click()
    cy.get(`#${IDS.rpe_guide_table}`).should('exist')

    // Collapse
    cy.get(`#${IDS.rpe_guide_toggle}`).click()
    cy.get(`#${IDS.rpe_guide_table}`).should('not.exist')
  })
})

// ---------------------------------------------------------------------------
// 7. RPE Section — info tooltip
// ---------------------------------------------------------------------------

describe('RPE Section — info tooltip', () => {
  beforeEach(() => {
    stubSupporting()
    stubActivity()
    cy.setupApiAuthCookies()
    visitAndWait()
  })

  it('info tooltip appears on hover over info trigger', () => {
    cy.get(`#${IDS.rpe_info_trigger}`).scrollIntoView().focus()
    cy.get(`#${IDS.rpe_info_tooltip}`).should('exist')
  })
})
